// src/services/trainsApi.js
// Uses trains.json (847 entries) for offline scheduling + server API when available

import { STATIONS } from '../data/transitData';
import SCHEDULE from '../data/trainSchedule.json';

const API_BASE = process.env.REACT_APP_API_URL || 'http://localhost:4000';

/* ── Current time as HH:MM ─────────────────────────────── */
function nowHHMM() {
  const d = new Date();
  return `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
}

/* ── Add minutes to HH:MM string ──────────────────────── */
function addMins(timeStr, mins) {
  if (!timeStr || timeStr === '—') return '—';
  const [h, m] = timeStr.split(':').map(Number);
  const total  = h * 60 + m + Math.round(mins);
  return `${String(Math.floor(total / 60) % 24).padStart(2,'0')}:${String(total % 60).padStart(2,'0')}`;
}

/* ── Convert HH:MM to total minutes since midnight ─────── */
function toMins(timeStr) {
  const [h, m] = timeStr.split(':').map(Number);
  return h * 60 + m;
}

/* ── Pick next 3 trains from trainSchedule.json ────────────
   Steps:
   1. Filter schedule to trains going in right direction
   2. Compute departure time FROM boarding station (not Virar)
   3. Filter to trains that haven't left your station yet
   4. Sort and return 3 soonest
   ────────────────────────────────────────────────────────── */
function getScheduleTrains(fromStation, toStation, limit = 3) {
  const fromName = fromStation?.name || String(fromStation);
  const toName   = toStation?.name   || String(toStation);
  const fromId   = fromStation?.id   || 0;
  const toId     = toStation?.id     || 0;

  if (!fromName || !toName) return [];

  const now        = nowHHMM();
  const nowMinutes = toMins(now);
  const goingSouth = fromId < toId;

  // Speed assumptions: Fast = 4 min/station, Slow = 6 min/station
  const SPEED = { Fast: 4, Slow: 6 };

  const ALL_STATION_NAMES = [
    'Virar','Nalasopara','Vasai Road','Naigaon',
    'Bhayandar','Mira Road','Dahisar','Borivali'
  ];

  const results = [];

  for (const train of SCHEDULE) {
    const originName = train.from;
    const destName   = train.to;

    // Train must be going the right direction
    const originIdx = ALL_STATION_NAMES.indexOf(originName);
    const destIdx   = ALL_STATION_NAMES.indexOf(destName);
    const fromIdx   = ALL_STATION_NAMES.indexOf(fromName);
    const toIdx     = ALL_STATION_NAMES.indexOf(toName);

    if (originIdx === -1 || destIdx === -1 || fromIdx === -1 || toIdx === -1) continue;

    // Direction check: train must cover from→to
    const trainGoingSouth = originIdx < destIdx;
    if (trainGoingSouth !== goingSouth) continue;

    // Train must start at or before boarding station, end at or after destination
    if (goingSouth) {
      if (originIdx > fromIdx || destIdx < toIdx) continue;
    } else {
      if (originIdx < fromIdx || destIdx > toIdx) continue;
    }

    // How many stations from train origin to boarding station?
    const stationsOffset = Math.abs(fromIdx - originIdx);
    const minsPerStation = SPEED[train.type] || 5;
    const boardingOffset = stationsOffset * minsPerStation;

    // Actual departure time from boarding station
    const departFromOrigin = train.departure;
    const departAtBoarding = addMins(departFromOrigin, boardingOffset);
    const departMinutes    = toMins(departAtBoarding);

    // Only keep trains that haven't left the boarding station yet
    // Use a 1-minute buffer so current-minute train is excluded
    if (departMinutes <= nowMinutes) continue;

    // Arrival at destination
    const stationsOnLeg = Math.abs(toIdx - fromIdx);
    const arrivalTime   = addMins(departAtBoarding, stationsOnLeg * minsPerStation);

    results.push({
      id:            train.trainNumber,
      trainNumber:   train.trainNumber,
      name:          train.name,
      type:          train.type,
      departure:     departAtBoarding,
      nextTime:      departAtBoarding,
      arrival:       arrivalTime,
      platform:      goingSouth
                       ? (train.type === 'Fast' ? 1 : 3)
                       : (train.type === 'Fast' ? 2 : 4),
      platform_south: train.type === 'Fast' ? 1 : 3,
      fromStation:   STATIONS.find(s => s.name === fromName) || null,
      toStation:     STATIONS.find(s => s.name === toName)   || null,
    });
  }

  // Sort by departure time and return top N
  results.sort((a, b) => toMins(a.departure) - toMins(b.departure));
  return results.slice(0, limit);
}

/* ── Main export: try server first, fall back to schedule ── */
export async function fetchNextTrains(fromStation, toStation, limit = 3) {
  const fromName = fromStation?.name || fromStation;
  const toName   = toStation?.name   || toStation;

  try {
    const url = `${API_BASE}/trains/next?from=${encodeURIComponent(fromName)}&to=${encodeURIComponent(toName)}&limit=${limit}`;
    const res  = await fetch(url, { signal: AbortSignal.timeout(3000) });
    if (!res.ok) throw new Error(`Server ${res.status}`);
    const json = await res.json();

    if (json.success && json.data.length > 0) {
      // Normalise server response + recalculate boarding-station offset
      const normalised = json.data.map(t => normaliseServerTrain(t, fromStation, toStation));
      return { source: 'api', trains: normalised };
    }
    throw new Error('Empty');
  } catch {
    // Use local trainSchedule.json — always accurate to current time
    const trains = getScheduleTrains(fromStation, toStation, limit);
    return { source: 'local', trains };
  }
}

/* ── Normalise server train data ───────────────────────── */
function normaliseServerTrain(t, fromStation, toStation) {
  const fromSt = STATIONS.find(s => s.name.toLowerCase() === (t.from || t.fromStation || '').toLowerCase());
  const toSt   = STATIONS.find(s => s.name.toLowerCase() === (t.to   || t.toStation   || '').toLowerCase());
  return {
    id:            t.trainNumber,
    trainNumber:   t.trainNumber,
    name:          t.name,
    type:          t.type,
    nextTime:      t.departure,
    departure:     t.departure,
    arrival:       t.arrival || '—',
    platform:      t.type === 'Fast' ? 1 : 3,
    platform_south:t.type === 'Fast' ? 1 : 3,
    stops:         (t.stops || []).map(name => { const s = STATIONS.find(x => x.name === name); return s?.id || null; }).filter(Boolean),
    fromStation:   fromSt || null,
    toStation:     toSt   || null,
  };
}

export async function checkServerHealth() {
  try {
    const res  = await fetch(`${API_BASE}/health`, { signal: AbortSignal.timeout(2000) });
    const json = await res.json();
    return json.status === 'ok';
  } catch { return false; }
}
